@namespace Lumeo

<kbd class="@CssClass" @attributes="AdditionalAttributes">@ChildContent</kbd>

@code {
    /// <summary>The key or shortcut label (e.g. <c>"⌘"</c>, <c>"Ctrl"</c>, <c>"Esc"</c>).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Size of the badge. Defaults to <see cref="Lumeo.Size.Md"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;

    /// <summary>Additional CSS classes merged onto the root <c>kbd</c> element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root <c>kbd</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("pointer-events-none inline-flex select-none items-center gap-1 rounded border border-border/50 bg-muted font-mono font-medium text-muted-foreground", SizeClasses, Class);

    private string SizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-5 px-1 text-[10px]",
        Lumeo.Size.Lg => "h-6 px-2 text-xs",
        _ => "h-5 px-1.5 text-[11px]"
    };
}
